diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index ecbc13d489eb..e49dd230ade2 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -1677,9 +1677,30 @@ bool VectorCombine::foldShuffleOfBinops(Instruction &I) {
     if (llvm::is_contained(OldMask, PoisonMaskElem) && BO->isIntDivRem())
       return false;
     IsCommutative = BinaryOperator::isCommutative(BO->getOpcode());
-  } else if (match(LHS, m_Cmp(Pred, m_Value(X), m_Value(Y))) &&
-             match(RHS, m_SpecificCmp(Pred, m_Value(Z), m_Value(W)))) {
-    IsCommutative = cast<CmpInst>(LHS)->isCommutative();
+  } else if (auto *CmpLHS = dyn_cast<CmpInst>(LHS)) {
+    if (auto *CmpRHS = dyn_cast<CmpInst>(RHS)) {
+      // Get the full predicates including samesign information
+      CmpPredicate PredLHS = CmpPredicate::get(CmpLHS);
+      CmpPredicate PredRHS = CmpPredicate::get(CmpRHS);
+      
+      // Only combine if both comparisons have identical predicates,
+      // including samesign flags
+      if (static_cast<CmpInst::Predicate>(PredLHS) == 
+          static_cast<CmpInst::Predicate>(PredRHS) &&
+          PredLHS.hasSameSign() == PredRHS.hasSameSign()) {
+        Pred = PredLHS;
+        X = CmpLHS->getOperand(0);
+        Y = CmpLHS->getOperand(1);
+        Z = CmpRHS->getOperand(0);
+        W = CmpRHS->getOperand(1);
+        IsCommutative = CmpLHS->isCommutative();
+      } else {
+        return false;
+      }
+    } else {
+      return false;
+    }
+  }
   } else
     return false;

